            prefix[i] = prefix[i-1] + nums[i];
        } else {
            prefix[i] = nums[i];
        }
    }

    // Compute suffix sums where suffix[i] is the sum of the increasing sequence starting at i
    suffix[n-1] = nums[n-1];
    for (int i = n-2; i >= 0; --i) {
        if (nums[i] < nums[i+1]) {
            suffix[i] = suffix[i+1] + nums[i];
        } else {
            suffix[i] = nums[i];
        }
    }

    // Compute the maximum prefix sum up to each index
    vector<long long> max_prefix(n, 0);
    max_prefix[0] = prefix[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = max(max_prefix[i-1], prefix[i]);
    }

    // Compute the maximum suffix sum from each index
    vector<long long> max_suffix(n, 0);
    max_suffix[n-1] = suffix[n-1];
    for (int i = n-2; i >= 0; --i) {
        max_suffix[i] = max(max_suffix[i+1], suffix[i]);
    }

    // Compute the sum of the decreasing sequence between p and q
    vector<long long> decreasing_sum(n, 0);
    decreasing_sum[0] = nums[0];
    for (int i = 1; i < n; ++i) {
        if (nums[i] < nums[i-1]) {
            decreasing_sum[i] = decreasing_sum[i-1] + nums[i];
        } else {
            decreasing_sum[i] = nums[i];
        }
    }

    long long max_sum = LLONG_MIN;
    for (int p = 1; p < n - 2; ++p) {
        for (int q = p + 1; q < n - 1; ++q) {
            if (nums[p] > nums[q]) {
                long long current_sum = max_prefix[p-1] + decreasing_sum[q] - nums[p] + max_suffix[q+1];
                if (current_sum > max_sum) {
                    max_sum = current_sum;
                }
            }
        }
    }

    return max_sum;
